sys_ui_page.client_script:
initPage();

// Use this function to initialize variables at page load
function initPage() {
	// set a default radio button as selected
	gel('activeTaskOnly').checked = true;
}

// when the label is clicked update the radio button
function labelClick (value){
	gel(value).checked = true;
}

// dialog_button id="cancel" was clicked, user does not want to reopen the task
function onCancel() {
	// below will auto close popup
	GlideDialogWindow.get().destroy();
	return false;
}

// dialog_button id="submit" was clicked, user confirms wanting to reopen the task
function onSubmit() {
	// clear the previous modified to allow clean post back with the values passed in
	g_form.modified=false;
	return true;
}

sys_ui_page.processing_script:
changeTaskerNumber();

function changeTaskerNumber() {
	var th = new TaskerHelpers();
	var oTasksUpdated;
	var ou_id = sysid;
	var msgEnd;

	var formValues = form_values;
	var oFormValues = JSON.parse(formValues);
	var gr_ou = new GlideRecordSecure("x_153465_discovert_discover_office_hierarchy");
	if(gr_ou.get(sysid)){
		for(var i in oFormValues){
			var field = oFormValues[i];
			var name = field.name.split('.')[1];
			if(name.length <=0){
				// if no . in the name, reset to original value
				name = field.name;
			}
			gr_ou.setValue(name, field.value);
		}
		gr_ou.update();

		if(updateType == "activeTasksOnly"){ //comes from radio input tag name attribute
			oTasksUpdated = th.updateTaskerNumber(ou_id, true);
		}else if(updateType == "allTasks"){
			oTasksUpdated = th.updateTaskerNumber(ou_id, false);
		}
		if(updateType != "futureTasks"){
			msgEnd = gs.getMessage("Tasker - The number of Tasker Numbers updated in the Organizational Unit with Abbreviation [{0}]. was [{1}]").replace('{0}',oTasksUpdated.ou_abbreviation).replace('{1}',oTasksUpdated.tasksUpdated);
			gs.addInfoMessage(msgEnd);
		}
	}

	response.sendRedirect("/x_153465_discovert_discover_office_hierarchy.do?sys_id=" + sysid);
}
